// GET /api/v1/league/:configId/strategies-ranking?strategy=KEY — Hit Rate réel par équipe sur matchs archivés
if (pathname.startsWith('/api/v1/league/') && pathname.endsWith('/strategies-ranking') && req.method === 'GET') {
  const m = pathname.match(/^\/api\/v1\/league\/([^/]+)\/strategies-ranking$/);
  if (!m) return jsonResponse(res, 400, { error: 'Path invalide' });
  let configId = parseInt(m[1]);
  // Disambiguation BSD id → config_id
  const bsdMap = bsdConfig.mapping?.bsd_to_config?.[m[1]];
  if (bsdMap?.config_id) configId = bsdMap.config_id;
  const strategyKey = query.strategy || 'BTTS_YES';
  const leagueCfg = leaguesConfig.leagues.find(l => l.id === configId);
  if (!leagueCfg) return jsonResponse(res, 404, { error: 'Ligue introuvable', configId });

  const oddsKey = leagueCfg.odds_key;
  const archived = (db.archive_matches || []).filter(a => a.sport === oddsKey);

  // Predicate function par stratégie
  const predicates = {
    BTTS_YES:   (hs, as, isHome) => hs > 0 && as > 0,
    OVER_2_5:   (hs, as)         => (hs + as) >= 3,
    OVER_1_5:   (hs, as)         => (hs + as) >= 2,
    UNDER_2_5:  (hs, as)         => (hs + as) <= 2,
    VERROU_TACTIQUE: (hs, as)    => (hs + as) <= 3,
    CS_00:      (hs, as)         => hs === 0 && as === 0,
    DRAW:       (hs, as)         => hs === as,
    HOME_WIN:   (hs, as, isHome) => isHome === true && hs > as,
    AWAY_WIN:   (hs, as, isHome) => isHome === false && as > hs,
    DC_HOME:    (hs, as, isHome) => isHome === true && hs >= as,
    DC_AWAY:    (hs, as, isHome) => isHome === false && as >= hs,
  };
  // Stratégies non-supportées (corners / mi-temps / golden gap)
  const unsupported = ['ANGLE_CORNERS', 'OVER_6_5_CORNERS', 'GOLDEN_PPG_GAP', 'HT_HOME_FT_HOME', 'HT_UNDER_FT_OVER'];
  if (unsupported.includes(strategyKey)) {
    return jsonResponse(res, 200, {
      success: true, leagueId: configId, strategy: strategyKey,
      unsupported: true,
      reason: 'Données corners / mi-temps non disponibles dans archive_matches',
      ranking: [],
    });
  }
  const predicate = predicates[strategyKey];
  if (!predicate) return jsonResponse(res, 400, { error: 'Stratégie inconnue', strategy: strategyKey });

  // Extraction score depuis live_score ou goals
  const extractScore = (m) => {
    if (m.live_score) {
      const [h, a] = m.live_score.split('-').map(s => parseInt(s));
      if (!isNaN(h) && !isNaN(a)) return [h, a];
    }
    if (m.goals && typeof m.goals.home === 'number' && typeof m.goals.away === 'number') {
      return [m.goals.home, m.goals.away];
    }
    return null;
  };

  // Agréger per team
  const stats = new Map();
  for (const match of archived) {
    const sc = extractScore(match);
    if (!sc) continue;
    const [hs, as] = sc;
    const hTeam = match.home_team;
    const aTeam = match.away_team;
    if (!hTeam || !aTeam) continue;
    // Home team
    if (!stats.has(hTeam)) stats.set(hTeam, { team: hTeam, played: 0, validated: 0 });
    const hS = stats.get(hTeam);
    hS.played++;
    if (predicate(hs, as, true)) hS.validated++;
    // Away team
    if (!stats.has(aTeam)) stats.set(aTeam, { team: aTeam, played: 0, validated: 0 });
    const aS = stats.get(aTeam);
    aS.played++;
    if (predicate(hs, as, false)) aS.validated++;
  }

  // Convertir en ranking
  const ranking = [...stats.values()]
    .filter(s => s.played > 0)
    .map(s => ({
      team: s.team,
      played: s.played,
      validated: s.validated,
      hitRate: Math.round((s.validated / s.played) * 100),
    }))
    .sort((a, b) => b.hitRate - a.hitRate || b.played - a.played)
    .map((s, i) => ({ ...s, rank: i + 1 }));

  return jsonResponse(res, 200, {
    success: true,
    leagueId: configId,
    strategy: strategyKey,
    sampleSize: archived.length,
    ranking,
  });
}

// GET /api/v1/standings/:leagueId — classement consolidé (accepte config_id OU BSD id)
if (pathname.startsWith('/api/v1/standings/') && req.method === 'GET') {
  const rawId = decodeURIComponent(pathname.slice('/api/v1/standings/'.length));
  console.log(`  [DEBUG STANDINGS] Route called id=${rawId}`);
  if (!rawId || rawId === 'undefined' || rawId === 'null' || isNaN(parseInt(rawId))) {
    return jsonResponse(res, 400, { success: false, message: 'leagueId invalide' });
  }
  let configId = parseInt(rawId);
  const bsdMapEntry = bsdConfig.mapping?.bsd_to_config?.[String(rawId)];
  if (bsdMapEntry?.config_id) configId = bsdMapEntry.config_id;

  // Ligue couverte BSD → on n'affiche QUE des lignes BSD/ESPN. Les lignes
  // `api-football` (plan gratuit = saison N-1 TERMINÉE) sont ignorées : elles
  // ne doivent jamais polluer le classement (cause du bug "Clsst figé").
  const _bsdCoveredLeague = BSD_CONFIG_TO_BSD[String(configId)] != null;
  const buildRows = () => Object.entries(db.teamStats)
    .filter(([, s]) => s.leagueId === configId && s._real && s.rank &&
      !(_bsdCoveredLeague && s._source === 'api-football'))
    .map(([tKey, s]) => {
      // PRIORITÉ raw counts (s._raw) — sinon fallback home/away (qui contiennent des %, peu fiable)
      const raw = s._raw || {};
      const played = raw.played != null ? raw.played : (s?.home?.played || 0);
      const wins = raw.wins != null ? raw.wins : null;
      const draws = raw.draws != null ? raw.draws : null;
      const losses = raw.losses != null ? raw.losses : null;
      const gf = raw.gf != null ? raw.gf : null;
      const ga = raw.ga != null ? raw.ga : null;
      const pts = raw.pts != null ? raw.pts : (wins != null && draws != null ? wins * 3 + draws : null);
      const ppg = (played && pts != null) ? parseFloat((pts / played).toFixed(2)) : (s?.home?.ppg ?? null);
      const avgFor = (played && gf != null) ? parseFloat((gf / played).toFixed(2)) : (s?.home?.avgScored ?? null);
      const avgAg  = (played && ga != null) ? parseFloat((ga / played).toFixed(2)) : (s?.home?.avgConceded ?? null);
      return {
        team: tKey,
        rank: s.rank,
        form: s.form || '',
        ppg,
        played,
        wins,
        draws,
        losses,
        pts,
        gf,
        ga,
        avgFor,
        avgAg,
        _source: s._source || null,
      };
    })
    .sort((a, b) => (a.rank || 99) - (b.rank || 99));

  let rows = buildRows();
  let refetched = false;

  // Ligues ESPN (J-League…) : source autoritaire saison en cours. On rafraîchit
  // même si des lignes existent quand elles ne proviennent pas d'ESPN (lignes
  // API-Football périmées d'une saison terminée).
  const espnSlug = ESPN_STANDINGS_SLUG[configId];
  const stale = espnSlug && rows.length && rows.some(r => r._source !== 'espn');
  // Ligues BSD : si la table mélange du BSD frais et des lignes API-Football
  // périmées (saison terminée d'un ancien run), forcer un refetch + purge.
  const bsdLeagueId = BSD_CONFIG_TO_BSD[String(configId)];
  const mixedStale = !!bsdLeagueId && rows.length > 0 &&
    rows.some(r => r._source === 'api-football') &&
    rows.some(r => r._source === 'bsd');

  // On-demand fetch si vide OU périmé — rate-limited à 60s par ligue
  if (!rows.length || stale || mixedStale) {
    db._standingsRefetchTs = db._standingsRefetchTs || {};
    const last = db._standingsRefetchTs[configId] || 0;
    if ((Date.now() - last) > 60_000) {
      db._standingsRefetchTs[configId] = Date.now();
      try {
        let teams = null;
        if (espnSlug) {
          teams = await fetchESPNStandings(espnSlug, configId);
        }
        if (!teams || !Object.keys(teams).length) {
          if (bsdLeagueId && BSD_API_KEY) teams = await fetchBSDStandings(bsdLeagueId, configId);
        }
        if (teams && Object.keys(teams).length) {
          // Purge TOTALE des lignes de cette ligue avant injection : BSD/ESPN
          // renvoient la table complète et autoritaire. Sans purge totale,
          // des doublons au mauvais rang subsistent (ex: K League — lignes
          // api-football P33 saison N-1 cohabitant avec BSD P15).
          for (const k of Object.keys(db.teamStats)) {
            if (db.teamStats[k]?.leagueId === configId) delete db.teamStats[k];
          }
          Object.assign(db.teamStats, teams);
          db.statsUpdateByLeague[configId] = new Date().toISOString();
          refetched = true;
          rows = buildRows();
        }
      } catch (e) {
        console.warn(`  [DEBUG STANDINGS] on-demand refetch ligue ${configId} erreur:`, e.message);
      }
    }
  }

  return jsonResponse(res, 200, {
    success: true,
    leagueId: configId,
    count: rows.length,
    refetched,
    standings: rows,
  });
}

// GET /api/v1/corners/:matchId — Corner predictions (BSD history + Poisson)
if (pathname.startsWith('/api/v1/corners/') && req.method === 'GET') {
  const matchId = decodeURIComponent(pathname.slice('/api/v1/corners/'.length));
  if (!matchId || matchId === 'undefined' || matchId === 'null') {
    return jsonResponse(res, 400, { error: 'matchId invalide' });
  }
  return handleCornersRoute(res, matchId);
}

// ─── BSD Tennis — REST proxy + MCP passthrough ($5/mo Sports Addon) ─────────
// Flag BSD_TENNIS_ENABLED gate sans appel réseau. 402 BSD → 402 propre côté UI.

// Extrait la liste des matchs depuis la réponse BSD (paginée ou tableau direct).
function _extractBsdMatchesList(body) {
  if (!body) return [];
  if (Array.isArray(body)) return body;
  if (Array.isArray(body.results)) return body.results;
  if (Array.isArray(body.matches)) return body.matches;
  return [];
}

// ─── P0-5 — Log-diff : rang implicite Elo vs rang officiel ──────────────────
// Edge direct : les books pricent souvent au rang ATP/WTA. Si l'Elo classe un
// joueur bien mieux que son rang officiel → le book le sous-cote. 100 % local.
const _TENNIS_RANK_TTL_MS = 6 * 3600 * 1000;
const _tennisRankIndex = { ts: 0, byTour: null };

function _buildTennisRankIndex() {
  if (_tennisRankIndex.byTour && Date.now() - _tennisRankIndex.ts < _TENNIS_RANK_TTL_MS) {
    return _tennisRankIndex.byTour;
  }
  const byTour = {}; // tour → { eloPos:Map(lname→pos), official:Map(lname→{rank,d}) }
  for (const tour of ['ATP', 'WTA']) {
    const eloPos = new Map();
    const official = new Map();
    try {
      // Rang Elo restreint aux joueurs actifs (≈ 14 derniers mois) pour être
      // comparable à l'échelle du rang officiel courant (sinon les milliers de
      // joueurs historiques faussent la position).
      const cD = new Date(Date.now() - 425 * 86400000);
      const cutoffYmd = cD.getUTCFullYear() * 10000 + (cD.getUTCMonth() + 1) * 100 + cD.getUTCDate();
      const eloRows = sqldb.prepare(
        `SELECT player_name FROM tennis_elo
         WHERE tour = ? AND surface = 'ALL'
           AND last_match_date IS NOT NULL AND last_match_date >= ?
         ORDER BY elo DESC`
      ).all(tour, cutoffYmd);
      eloRows.forEach((r, i) => {
        if (r.player_name) eloPos.set(r.player_name.toLowerCase(), i + 1);
      });
      for (const side of ['winner', 'loser']) {
        const rows = sqldb.prepare(
          `SELECT LOWER(${side}_name) AS n, ${side}_rank AS rank, MAX(tourney_date) AS d
           FROM tennis_matches
           WHERE tour = ? AND ${side}_rank IS NOT NULL AND ${side}_name IS NOT NULL
           GROUP BY LOWER(${side}_name)`
        ).all(tour);
        for (const r of rows) {
          const prev = official.get(r.n);
          if (!prev || (r.d || 0) > prev.d) official.set(r.n, { rank: r.rank, d: r.d || 0 });
        }
      }
    } catch (_) { /* tables absentes — log-diff restera null */ }
    byTour[tour] = { eloPos, official };
  }
  _tennisRankIndex.byTour = byTour;
  _tennisRankIndex.ts = Date.now();
  return byTour;
}

// log_diff > 0 → Elo classe le joueur mieux que son rang officiel (value).
function tennisLogDiff(playerName, tour) {
  if (!playerName || !tour) return null;
  const T = String(tour).toUpperCase();
  const idx = _buildTennisRankIndex()[T];
  if (!idx) return null;
  const ln = playerName.trim().toLowerCase();
  const eloRank = idx.eloPos.get(ln);
  const off = idx.official.get(ln);
  if (!eloRank || !off || !off.rank) return null;
  return {
    elo_rank: eloRank,
    official_rank: off.rank,
    log_diff: parseFloat((Math.log(off.rank) - Math.log(eloRank)).toFixed(3)),
  };
}

// ─── P1-3 — Surface Speed Index (méthodo Tennis Abstract) ───────────────────
// Vitesse d'un tournoi = taux d'aces du tournoi rapporté à la moyenne de sa
// surface. > 100 = plus rapide (plus d'aces → avantage serveur). 100 % local.
// v1 : normalisation surface (l'ajustement serveur/retourneur individuel est
// une raffinement P1-3.1). Consommé par le modèle point-par-point P1-1.
const _TENNIS_SPEED_TTL_MS = 24 * 3600 * 1000;
const _tennisSpeedIndex = { ts: 0, byTourney: null };

function _buildSurfaceSpeedIndex() {
  if (_tennisSpeedIndex.byTourney && Date.now() - _tennisSpeedIndex.ts < _TENNIS_SPEED_TTL_MS) {
    return _tennisSpeedIndex.byTourney;
  }
  const byTourney = new Map(); // normTourneyName → { index, surface, samples }
  try {
    const surfAvg = {};
    for (const r of sqldb.prepare(
      `SELECT surface,
              SUM(COALESCE(w_ace,0)+COALESCE(l_ace,0)) AS aces,
              SUM(COALESCE(w_svpt,0)+COALESCE(l_svpt,0)) AS svpt
       FROM tennis_matches
       WHERE surface IS NOT NULL AND w_svpt IS NOT NULL
       GROUP BY surface`).all()) {
      if (r.svpt > 0) surfAvg[r.surface] = r.aces / r.svpt;
    }
    const rows = sqldb.prepare(
      `SELECT tourney_name AS name, surface,
              SUM(COALESCE(w_ace,0)+COALESCE(l_ace,0)) AS aces,
              SUM(COALESCE(w_svpt,0)+COALESCE(l_svpt,0)) AS svpt,
              COUNT(*) AS n
       FROM tennis_matches
       WHERE tourney_name IS NOT NULL AND surface IS NOT NULL AND w_svpt IS NOT NULL
       GROUP BY LOWER(tourney_name), surface
       HAVING svpt > 800`).all();
    for (const r of rows) {
      const base = surfAvg[r.surface];
      if (!base || base <= 0 || !r.svpt) continue;
      const idx = Math.round(100 * (r.aces / r.svpt) / base);
      const key = _normTournName(r.name);
      if (!key) continue;
      const prev = byTourney.get(key);
      if (!prev || r.n > prev.samples) {
        byTourney.set(key, { index: idx, surface: _mapSurfaceToElo(r.surface), samples: r.n });
      }
    }
  } catch (_) { /* tennis_matches absent — speed index indisponible */ }
  _tennisSpeedIndex.byTourney = byTourney;
  _tennisSpeedIndex.ts = Date.now();
  return byTourney;
}

// Renvoie { index, surface, samples } ou null. index 100 = vitesse moyenne
// de la surface ; > 100 rapide (boost serveur), < 100 lent.
function getTennisSurfaceSpeed(tournamentName) {
  if (!tournamentName) return null;
  const idx = _buildSurfaceSpeedIndex();
  if (!idx || idx.size === 0) return null;
  const t = _normTournName(tournamentName);
  if (!t) return null;
  if (idx.has(t)) return idx.get(t);
  for (const [n, v] of idx.entries()) {
    if (n.length >= 5 && (t.includes(n) || n.includes(t))) return v;
  }
  return null;
}

// ─── P1-4 — Fatigue & contexte joueur ──────────────────────────────────────
// Depuis tennis_matches (Sackmann peut accuser un léger retard) : charge des
// derniers matchs + rust + abandons récents → drapeaux anti-piège. 100 % local.
const _TENNIS_FATIGUE_TTL_MS = 12 * 3600 * 1000;
const _tennisFatigueCache = new Map();

function _ymdDaysAgo(ymd) {
  const d = _ymdToDays(ymd);
  if (d == null) return null;
  return Math.floor(Date.now() / 86400000) - d;
}

function computePlayerFatigue(playerName, tour) {
  if (!playerName || !tour) return null;
  const ck = `FAT|${tour}|${playerName.toLowerCase()}`;
  const cached = _tennisFatigueCache.get(ck);
  if (cached && Date.now() - cached.ts < _TENNIS_FATIGUE_TTL_MS) return cached.v;
  let v = null;
  try {
    const rows = sqldb.prepare(`
      SELECT tourney_date AS d, minutes, score,
        CASE WHEN LOWER(winner_name)=LOWER(?) THEN 1 ELSE 0 END AS won
      FROM tennis_matches
      WHERE (LOWER(winner_name)=LOWER(?) OR LOWER(loser_name)=LOWER(?)) AND tour=?
      ORDER BY tourney_date DESC, match_num DESC LIMIT 12
    `).all(playerName, playerName, playerName, tour);
    if (rows.length) {
      const lastD = rows[0].d;
      const daysSince = _ymdDaysAgo(lastD);
      const lastDdays = _ymdToDays(lastD);
      let min14 = 0, m14 = 0, min5 = 0;
      let recentRet = false;
      rows.forEach((r, i) => {
        const rd = _ymdToDays(r.d);
        if (lastDdays != null && rd != null && (lastDdays - rd) <= 14) {
          min14 += r.minutes || 0; m14++;
        }
        if (i < 5) {
          min5 += r.minutes || 0;
          if (r.score && /RET|W\/O|DEF|ABN/i.test(r.score)) recentRet = true;
        }
      });
      const flags = [];
      if (daysSince != null && daysSince > 60) flags.push('rust');       // longue inactivité
      if (recentRet) flags.push('recent_ret');                            // abandon récent (blessure)
      if (m14 >= 5 || min14 >= 600) flags.push('heavy_load');             // surcharge calendrier
      v = {
        days_since_last: daysSince,
        matches_14d: m14,
        minutes_14d: min14,
        minutes_last5: min5,
        recent_ret: recentRet,
        risk_flags: flags,
      };
    }
  } catch (_) { v = null; }
  _tennisFatigueCache.set(ck, { ts: Date.now(), v });
  return v;
}

// Construit la liste enrichie value-bets tennis :
// BSD matches scheduled  +  The Odds API h2h  →  devig 2-way  →  EV%  →  best_edge.
// Fallback ESPN si BSD désactivé ou en erreur (mode dégradé, sans surface ni rank).
// Cache du body assemblé : le build cold = ~20 s (420 matchs × helpers
// Elo/RPW/fatigue/logdiff). Sans ce cache le front time-out → "Erreur de
// chargement". Warm au boot. TTL court (cotes fraîches).
const _TENNIS_VB_TTL_MS = 4 * 60 * 1000;
// ⚠ Ces déclarations vivent dans la closure requête (ré-évaluées par appel).
// Singleton via globalThis pour persister le cache sur la vie du process.
const _tnsVBState = (globalThis.__tnsVBState ||= { cache: new Map(), rebuilding: new Set() });
const _tennisVBCache = _tnsVBState.cache;
const _tennisVBRebuilding = _tnsVBState.rebuilding;

// ─── Enrichment Snapshot (Solution A — Backend invincible) ──────────────────
// BSD scheduled list DROP les matchs qui passent in_progress → `enriched[]`
// perd l'enrichissement (predictions, set_model, predictive, powerscore,
// confidence_badge) → frontend reçoit du vide → colonnes "—". Le snapshot
// serveur conserve TOUJOURS la dernière version enrichie d'un match (par
// id BSD + paires de noms multi-tokens) et la ré-injecte au build suivant
// en mergeant le score live. Survit aux drops upstream, fonctionne au 1er
// hit pour tout client (pas de bootstrap navigateur requis).
const _TN_ENRICH_TTL_MS = 12 * 3600 * 1000;
const _tennisEnrichSnap = (globalThis.__tnEnrichSnap ||= new Map());

function _tnSrvNorm(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^\w\s.-]/g, ' ').replace(/\s+/g, ' ').trim();
}
function _tnSrvLastName(n) {
  const p = _tnSrvNorm(n).split(/\s+/).filter(Boolean);
  return p.length ? p[p.length - 1] : '';
}
function _tnSrvTokens(n) {
  return _tnSrvNorm(n).split(/\s+/).filter(t => t && t.length >= 3 && !/^[a-z]\.?$/.test(t));
}
function _tnSrvPairKey(p1, p2) {
  const a = _tnSrvNorm(p1), b = _tnSrvNorm(p2);
  if (!a || !b) return '';
  return [a, b].sort().join('|');
}
function _tnSrvPairLastKey(p1, p2) {
  const a = _tnSrvLastName(p1), b = _tnSrvLastName(p2);
  if (!a || !b) return '';
  return [a, b].sort().join('|');
}
function _tnSrvAllPairKeys(p1, p2) {
  const t1 = _tnSrvTokens(p1), t2 = _tnSrvTokens(p2);
  if (!t1.length || !t2.length) return [];
  const out = [];
  for (const a of t1) for (const b of t2) out.push([a, b].sort().join('|'));
  return out;
}
function _tnSrvEnrichSignal(e) {
  if (!e) return false;
  if (e.predictions && (e.predictions.elo || e.predictions.blended)) return true;
  if (e.predictive && e.predictive.prematch && e.predictive.prematch.length) return true;
  if (e.set_model) return true;
  if (e.confidence_badge) return true;
  if (e.player1 && (e.player1.powerscore != null || e.player1.l5_pts != null)) return true;
  if (e.player2 && (e.player2.powerscore != null || e.player2.l5_pts != null)) return true;
  return false;
}
function _tnSrvStoreSnap(e) {
  if (!e || !e.player1 || !e.player2) return;
  if (!_tnSrvEnrichSignal(e)) return;
  const p1 = e.player1.name, p2 = e.player2.name;
  if (!p1 || !p2) return;
  const entry = { ts: Date.now(), data: e };
  if (e.id != null) _tennisEnrichSnap.set('id:' + e.id, entry);
  const pk = _tnSrvPairKey(p1, p2); if (pk) _tennisEnrichSnap.set('pk:' + pk, entry);
  const lk = _tnSrvPairLastKey(p1, p2); if (lk && lk !== pk) _tennisEnrichSnap.set('lk:' + lk, entry);
  for (const k of _tnSrvAllPairKeys(p1, p2)) _tennisEnrichSnap.set('tk:' + k, entry);
}
function _tnSrvLookupSnap(lo) {
  if (!lo) return null;
  let hit = null;
  if (lo.id != null) hit = _tennisEnrichSnap.get('id:' + lo.id);
  const p1 = lo.player1 && lo.player1.name;
  const p2 = lo.player2 && lo.player2.name;
  if (!hit && p1 && p2) {
    const pk = _tnSrvPairKey(p1, p2);
    if (pk) hit = _tennisEnrichSnap.get('pk:' + pk);
  }
  if (!hit && p1 && p2) {
    const lk = _tnSrvPairLastKey(p1, p2);
    if (lk) hit = _tennisEnrichSnap.get('lk:' + lk);
  }
  if (!hit && p1 && p2) {
    for (const k of _tnSrvAllPairKeys(p1, p2)) {
      hit = _tennisEnrichSnap.get('tk:' + k);
      if (hit) break;
    }
  }
  if (!hit) return null;
  if (Date.now() - hit.ts > _TN_ENRICH_TTL_MS) return null;
  return hit.data;
}
function _tnSrvJanitor() {
  const now = Date.now();
  let dropped = 0;
  for (const [k, v] of _tennisEnrichSnap) {
    if (now - v.ts > _TN_ENRICH_TTL_MS) { _tennisEnrichSnap.delete(k); dropped++; }
  }
  if (dropped) console.log(`  [TennisSnap] janitor — ${dropped} entrées expirées`);
}
if (!globalThis.__tnSnapJanitorOn) {
  globalThis.__tnSnapJanitorOn = true;
  const _h = setInterval(_tnSrvJanitor, 60 * 60 * 1000);
  if (_h && typeof _h.unref === 'function') _h.unref();
}

// Wrapper stale-while-revalidate : le build cold = ~15-20 s (420 matchs ×
// helpers Elo/RPW/fatigue/logdiff). On sert toujours le cache (même périmé)
// instantanément + rebuild en arrière-plan. Seul le tout 1er appel (sans
// cache) est lent → couvert par le warm-up au boot. Évite le timeout UI.
async function buildTennisValueBets(opts = {}) {
  const dateClean = opts.date ? String(opts.date).replace(/[^0-9-]/g, '').slice(0, 10) : '';
  const key = dateClean || 'today';
  const hit = _tennisVBCache.get(key);
  if (hit) {
    // Build dégradé ESPN (BSD KO ce cycle) : TTL court 60 s → réessaie BSD vite
    // au lieu de figer des ids ESPN (detail mort) pendant 4 min.
    const _deg = hit.result && hit.result.body && hit.result.body.meta && hit.result.body.meta.match_source && hit.result.body.meta.match_source !== 'bsd';
    const _ttl = _deg ? 60 * 1000 : _TENNIS_VB_TTL_MS;
    if (Date.now() - hit.ts < _ttl) return hit.result;
    // Périmé : sert le stale tout de suite, rebuild en tâche de fond.
    if (!_tennisVBRebuilding.has(key)) {
      _tennisVBRebuilding.add(key);
      _buildTennisValueBetsCore(opts)
        .then(r => { if (r && r.status === 200) _tennisVBCache.set(key, { ts: Date.now(), result: r }); })
        .catch(e => console.warn('  [TennisVB] rebuild bg échec:', e.message))
        .finally(() => _tennisVBRebuilding.delete(key));
    }
    return hit.result;
  }
  // [FIX bug onglet tennis — v4] Aucun cache : NE PLUS bloquer la requête.
  // Le build cold (~20 s, ~420 matchs, boucle CPU) dépassait le timeout
  // proxy/UI → connexion coupée → "Erreur réseau" + Chargement figé, et la
  // boucle synchrone empêchait tout Promise.race/timeout de tirer.
  // → build lancé EN FOND (avec yields event-loop), réponse "loading"
  //   immédiate. Le front ré-essaie ; dès cache prêt → vraies données.
  if (!_tennisVBRebuilding.has(key)) {
    _tennisVBRebuilding.add(key);
    _buildTennisValueBetsCore(opts)
      .then(r => { if (r && r.status === 200) _tennisVBCache.set(key, { ts: Date.now(), result: r }); })
      .catch(e => console.warn('  [TennisVB] cold build bg échec:', e && e.message || e))
      .finally(() => _tennisVBRebuilding.delete(key));
  }
  return { status: 200, body: { count: 0, matches: [], meta: { loading: true, building: true } } };
}
// Pont scope : le warm-up boot (_sackmannBootSync IIFE) ne voit pas cette
// closure → on expose la fn via globalThis pour le warm-up.
try { globalThis.__tennisVBWarm = buildTennisValueBets; } catch (_) { /* noop */ }

// ── BSD Tennis Predictions (ML CatBoost) — bulk → Map (PAS de N+1) ───────────
// Branche les prédictions BSD au tableau : proba ML, confiance, O/U sets/jeux,
// 1er set. /api/v2/predictions/ est paginé bulk → 1 fetch couvre tout le slate.
function _tnNameKey(a, b) {
  const x = normName(a), y = normName(b);
  return [x, y].sort().join('|');
}
function _predListToMap(list) {
  const m = new Map();
  for (const p of (list || [])) {
    const mt = p && p.match;
    if (!mt) continue;
    if (mt.id != null) m.set('id:' + mt.id, p);
    const n1 = mt.player1 && (mt.player1.name || mt.player1.short_name);
    const n2 = mt.player2 && (mt.player2.name || mt.player2.short_name);
    if (n1 && n2) {
      const k = 'pk:' + _tnNameKey(n1, n2);
      if (!m.has(k)) m.set(k, p);
    }
  }
  return m;
}
async function fetchBSDTennisPredictions(dateClean) {
  if (!BSD_TENNIS_ENABLED) return new Map();
  const ck = `bsd_tennis_preds_${dateClean || 'upcoming'}`;
  const cached = apiCacheGet(ck);
  if (cached) return _predListToMap(cached);
  const out = [];
  let suffix = dateClean
    ? `/api/v2/predictions/?date_from=${encodeURIComponent(dateClean)}&date_to=${encodeURIComponent(dateClean)}&limit=200`
    : `/api/v2/predictions/?upcoming=true&limit=200`;
  for (let page = 0; page < 6 && suffix; page++) {
    let r;
    try { r = await bsdTennisFetch(suffix); } catch (e) { break; }
    if (!r || r.status !== 200 || !r.data) break;
    const res = Array.isArray(r.data) ? r.data : (Array.isArray(r.data.results) ? r.data.results : []);
    if (!res.length) break;
    out.push(...res);
    const nx = r.data && r.data.next ? String(r.data.next) : null;
    suffix = (nx && nx.includes('/tennis')) ? nx.slice(nx.indexOf('/tennis') + '/tennis'.length) : null;
  }
  // Bzzoiro régénère les prédictions toutes les 15 min (job planifié) → cache
  // aligné 15 min pour ne jamais servir une prédiction d'un cycle périmé.
  if (out.length) apiCacheSet(ck, out, 'bsd_tennis', 15 * 60 * 1000);
  console.log(`  [TennisPred BSD] ${out.length} prédictions chargées (${dateClean || 'upcoming'})`);
  return _predListToMap(out);
}

// ── SPRINT 1 — Calibration ML BSD (via was_winner_correct backtest) ──────────
// Mesure la fiabilité RÉELLE du modèle BSD : accuracy par bucket de confiance
// + par surface. Alimente le badge confiance (S1) ET le blend dynamique (S2).
let _bsdTennisCalib = { ts: 0, data: null };
function _wilsonLow(p, n) {
  if (!n) return 0;
  const z = 1.96, ph = p, d = 1 + z * z / n;
  const c = ph + z * z / (2 * n);
  const m = z * Math.sqrt((ph * (1 - ph) + z * z / (4 * n)) / n);
  return Math.max(0, (c - m) / d);
}
async function buildBSDTennisCalibration() {
  if (!BSD_TENNIS_ENABLED) return null;
  if (_bsdTennisCalib.data && Date.now() - _bsdTennisCalib.ts < 6 * 3600 * 1000) return _bsdTennisCalib.data;
  const ck = 'bsd_tennis_calib_raw';
  let raw = apiCacheGet(ck);
  if (!raw) {
    const out = [];
    // upcoming=false = prédictions RÉGLÉES (was_winner_correct/actual_winner
    // remplis). Le filtre date_from/date_to renvoie l'upcoming (tout null).
    let suffix = `/api/v2/predictions/?upcoming=false&limit=200`;
    for (let p = 0; p < 8 && suffix; p++) {
      let r; try { r = await bsdTennisFetch(suffix); } catch (e) { break; }
      if (!r || r.status !== 200 || !r.data) break;
      const res = Array.isArray(r.data) ? r.data : (Array.isArray(r.data.results) ? r.data.results : []);
      if (!res.length) break;
      out.push(...res);
      const nx = r.data && r.data.next ? String(r.data.next) : null;
      suffix = (nx && nx.includes('/tennis')) ? nx.slice(nx.indexOf('/tennis') + '/tennis'.length) : null;
    }
    raw = out;
    if (out.length) apiCacheSet(ck, out, 'bsd_tennis', 6 * 3600 * 1000);
  }
  const settled = (raw || []).filter(p => p && p.was_winner_correct != null && p.confidence != null);
  const bucket = c => Math.min(9, Math.max(5, Math.floor(Number(c) / 10))); // 50-100 → 5..9
  const byConf = {}; const bySurf = {}; let okN = 0, brierSum = 0, brierN = 0;
  for (const p of settled) {
    const ok = p.was_winner_correct === true || p.was_winner_correct === 1 ? 1 : 0;
    okN += ok;
    const bk = bucket(p.confidence);
    (byConf[bk] = byConf[bk] || { ok: 0, n: 0 }).n++; byConf[bk].ok += ok;
    const surf = (p.match && p.match.tournament && p.match.tournament.surface) || 'unknown';
    (bySurf[surf] = bySurf[surf] || { ok: 0, n: 0 }).n++; bySurf[surf].ok += ok;
    const pp = parseFloat(p.prob_player1_wins);
    if (Number.isFinite(pp) && p.actual_winner != null) {
      const y = (p.actual_winner === 1) ? 1 : 0;
      brierSum += Math.pow(pp / 100 - y, 2); brierN++;
    }
  }
  // Bzzoiro expose 3 flags réglés : winner (ci-dessus) + over_sets + over_games.
  // Les marchés totaux sont scorés par le modèle ML mais leur fiabilité RÉELLE
  // n'était jamais mesurée → le moteur prédictif leur appliquait la confiance
  // du vainqueur (biais). On mesure ici l'accuracy propre de chaque marché.
  const mkt = { over_sets: { ok: 0, n: 0 }, over_games: { ok: 0, n: 0 } };
  for (const p of (raw || [])) {
    if (!p) continue;
    if (p.was_over_sets_correct != null) {
      mkt.over_sets.n++;
      if (p.was_over_sets_correct === true || p.was_over_sets_correct === 1) mkt.over_sets.ok++;
    }
    if (p.was_over_games_correct != null) {
      mkt.over_games.n++;
      if (p.was_over_games_correct === true || p.was_over_games_correct === 1) mkt.over_games.ok++;
    }
  }
  const finM = o => ({ acc: o.n ? o.ok / o.n : null, n: o.n, low: o.n ? _wilsonLow(o.ok / o.n, o.n) : 0 });
  const fin = o => Object.fromEntries(Object.entries(o).map(([k, v]) => [k, { acc: v.n ? v.ok / v.n : null, n: v.n, low: v.n ? _wilsonLow(v.ok / v.n, v.n) : 0 }]));
  const data = {
    n: settled.length,
    accuracy: settled.length ? okN / settled.length : null,
    brier: brierN ? parseFloat((brierSum / brierN).toFixed(4)) : null,
    by_confidence: fin(byConf),
    by_surface: fin(bySurf),
    by_market: { over_sets: finM(mkt.over_sets), over_games: finM(mkt.over_games) },
  };
  _bsdTennisCalib = { ts: Date.now(), data };
  const _mAcc = m => (m && m.acc != null) ? `${(m.acc * 100).toFixed(1)}%/n${m.n}` : '–';
  console.log(`  [TennisCalib BSD] n=${data.n} acc=${data.accuracy != null ? (data.accuracy * 100).toFixed(1) : '–'}% brier=${data.brier} | sets=${_mAcc(data.by_market.over_sets)} games=${_mAcc(data.by_market.over_games)}`);
  return data;
}
function _calibBadge(calib, confidence, surface) {
  if (!calib || confidence == null) return null;
  const bk = Math.min(9, Math.max(5, Math.floor(Number(confidence) / 10)));
  const c = calib.by_confidence[bk];
  const s = surface && calib.by_surface[surface];
  const acc = (c && c.n >= 30) ? c.acc : (calib.accuracy);
  const low = (c && c.n >= 30) ? c.low : 0;
  const n = (c && c.n) || calib.n || 0;
  let level = 'grey';
  if (n >= 30 && low >= 0.58) level = 'green';
  else if (n >= 20 && acc != null && acc >= 0.53) level = 'amber';
  else if (n >= 20) level = 'red';
  return {
    level, accuracy: acc != null ? parseFloat((acc * 100).toFixed(1)) : null,
    sample: n, ci_low: parseFloat((low * 100).toFixed(1)),
    surface_acc: s && s.n >= 20 ? parseFloat((s.acc * 100).toFixed(1)) : null,
    surface_n: s ? s.n : 0,
  };
}

// ── SPRINT 1 — Rankings BSD (momentum) ───────────────────────────────────────
let _bsdTennisRank = { ts: 0, byKey: null };
async function buildBSDTennisRankIndex() {
  if (!BSD_TENNIS_ENABLED) return new Map();
  if (_bsdTennisRank.byKey && Date.now() - _bsdTennisRank.ts < 6 * 3600 * 1000) return _bsdTennisRank.byKey;
  const byKey = new Map();
  for (const type of ['ATP', 'WTA']) {
    let suffix = `/api/v2/rankings/?type=${type}&limit=500`;
    for (let p = 0; p < 4 && suffix; p++) {
      let r; try { r = await bsdTennisFetch(suffix); } catch (e) { break; }
      if (!r || r.status !== 200 || !r.data) break;
      const res = Array.isArray(r.data) ? r.data : (Array.isArray(r.data.results) ? r.data.results : []);
      if (!res.length) break;
      for (const e of res) {
        const nm = e.player && (e.player.name || e.player.short_name);
        if (!nm) continue;
        byKey.set(normName(nm), {
          position: e.position ?? null, previous_position: e.previous_position ?? null,
          points: e.points ?? null, previous_points: e.previous_points ?? null,
          best_position: e.best_position ?? null, type,
        });
      }
      const nx = r.data && r.data.next ? String(r.data.next) : null;
      suffix = (nx && nx.includes('/tennis')) ? nx.slice(nx.indexOf('/tennis') + '/tennis'.length) : null;
    }
  }
  _bsdTennisRank = { ts: Date.now(), byKey };
  console.log(`  [TennisRank BSD] ${byKey.size} joueurs indexés`);
  return byKey;
}

// [FIX bug 5o0] Pont globalThis pour les warmers tennis — même classe de bug
// que __tennisVBWarm (cf. ~25492) : ces fns top-level ne sont pas résolues
// depuis le scope de pollTennisLive (« fetchBSDTennisPredictions is not
// defined »). On les expose ici (scope où elles sont liées) ; pollTennisLive
// les appelle via globalThis avec garde typeof.
try {
  globalThis.__tnWarmers = {
    fetchBSDTennisPredictions: (typeof fetchBSDTennisPredictions === 'function') ? fetchBSDTennisPredictions : null,
    buildBSDTennisCalibration: (typeof buildBSDTennisCalibration === 'function') ? buildBSDTennisCalibration : null,
    buildBSDTennisRankIndex: (typeof buildBSDTennisRankIndex === 'function') ? buildBSDTennisRankIndex : null,
    _buildTennisSurfaceIndex: (typeof _buildTennisSurfaceIndex === 'function') ? _buildTennisSurfaceIndex : null,
  };
} catch (_) { /* noop */ }

function _rankMomentum(rk) {
  if (!rk) return null;
  const dPos = (rk.previous_position != null && rk.position != null) ? (rk.previous_position - rk.position) : null;
  const dPts = (rk.previous_points != null && rk.points != null) ? (rk.points - rk.previous_points) : null;
  let trend = 'flat';
  if (dPos != null) trend = dPos >= 3 ? 'up' : dPos <= -3 ? 'down' : 'flat';
  return {
    position: rk.position, best_position: rk.best_position,
    delta_pos: dPos, delta_points: dPts,
    ceiling_gap: (rk.best_position != null && rk.position != null) ? rk.position - rk.best_position : null,
    trend,
  };
}

// ── SPRINT 2 — Fiabilité calibrée → blend dynamique + edge confiance ─────────
// reliability ∈ [0,1] dérivée de l'accuracy mesurée (was_winner_correct) pour
// le bucket de confiance + la surface. Remplace le blend Elo/BSD fixe 60/40.
function _calibReliability(calib, confidence, surface) {
  if (!calib || confidence == null) return null;
  const bk = Math.min(9, Math.max(5, Math.floor(Number(confidence) / 10)));
  const c = calib.by_confidence && calib.by_confidence[bk];
  const s = surface && calib.by_surface && calib.by_surface[surface];
  let acc = (c && c.n >= 30) ? c.acc : (calib.accuracy != null ? calib.accuracy : null);
  if (s && s.n >= 30 && s.acc != null) acc = (acc == null) ? s.acc : (acc * 0.6 + s.acc * 0.4);
  if (acc == null) return null;
  // 0.50 = pile/face → r=0 ; 0.90 → r=1. Brier global pénalise si mauvais.
  let r = Math.max(0, Math.min(1, (acc - 0.50) / 0.40));
  if (calib.brier != null) r *= Math.max(0.4, Math.min(1, 1 - (calib.brier - 0.18) / 0.30));
  return parseFloat(r.toFixed(3));
}
// Fiabilité ∈[0,1] d'un marché totaux (over_sets|over_games) dérivée de son
// accuracy RÉELLE mesurée (Bzzoiro was_over_*_correct). null si échantillon
// insuffisant (<20) → l'appelant applique alors une décote prudente.
function _calibMarketRel(calib, market) {
  if (!calib || !calib.by_market) return null;
  const m = calib.by_market[market];
  if (!m || m.acc == null || m.n < 20) return null;
  const r = Math.max(0, Math.min(1, (m.acc - 0.50) / 0.40));
  return parseFloat(r.toFixed(3));
}
function blendTennisProbsW(eloProb, bsdProb, wBsd) {
  if (!eloProb && !bsdProb) return null;
  if (!bsdProb) return { p1: eloProb.p1, p2: eloProb.p2, weights: { elo: 1, bsd: 0 }, method: 'elo_only' };
  if (!eloProb) return { p1: bsdProb.p1, p2: bsdProb.p2, weights: { elo: 0, bsd: 1 }, method: 'bsd_only' };
  if (wBsd == null) return blendTennisProbs(eloProb, bsdProb); // fallback statique 60/40
  const wb = Math.max(0.15, Math.min(0.75, wBsd)), we = 1 - wb;
  return {
    p1: parseFloat((we * eloProb.p1 + wb * bsdProb.p1).toFixed(4)),
    p2: parseFloat((we * eloProb.p2 + wb * bsdProb.p2).toFixed(4)),
    weights: { elo: parseFloat(we.toFixed(2)), bsd: parseFloat(wb.toFixed(2)) },
    method: 'blend_dynamic',
  };
}
// Trap-bet : le marché price un favori que le modèle calibré contredit, OU
// edge élevé sur un segment où le modèle BSD est peu fiable (badge red/grey).
function _computeTrapBet(fair, blended, badge, bestEv) {
  if (!fair || !blended) return null;
  const mFav = fair.p1 >= fair.p2 ? 'p1' : 'p2';
  const mFavPct = Math.max(fair.p1, fair.p2);
  const modelFav = blended.p1 >= blended.p2 ? 'p1' : 'p2';
  const modelFavPct = Math.max(blended.p1, blended.p2) * 100;
  // Contradiction franche : marché favori ≥60% mais modèle penche l'autre côté ≥55%.
  if (mFavPct >= 60 && modelFav !== mFav && modelFavPct >= 55) {
    return { flag: true, type: 'model_contradicts_market', market_fav: mFav, model_fav: modelFav,
      detail: `Marché ${mFavPct.toFixed(0)}% sur ${mFav} ; modèle ${modelFavPct.toFixed(0)}% sur ${modelFav}`, severity: 'high' };
  }
  // Edge "value" mais segment peu fiable → piège.
  if (bestEv && bestEv.ev > 4 && badge && (badge.level === 'red' || badge.level === 'grey')) {
    return { flag: true, type: 'unreliable_edge', detail: `EV +${bestEv.ev}% mais fiabilité modèle ${badge.accuracy != null ? badge.accuracy + '%' : 'n/d'} (n=${badge.sample})`, severity: 'medium' };
  }
  return { flag: false };
}
// Convergence totaux : O/U jeux BSD (expected_total_games) vs Markov local.
function _computeTotalsConvergence(bsdPred, gamesOU) {
  const exp = bsdPred && bsdPred.expected_total_games != null ? Number(bsdPred.expected_total_games) : null;
  if (exp == null || !gamesOU || !gamesOU.sets) return null;
  const setExp = [];
  for (const k of Object.keys(gamesOU.sets)) {
    const e = gamesOU.sets[k] && gamesOU.sets[k].exp_games;
    if (Number.isFinite(e)) setExp.push(e);
  }
  if (!setExp.length) return null;
  const meanSet = setExp.reduce((a, b) => a + b, 0) / setExp.length;
  // Sets moyens joués : BO5 ≈ 3.6, BO3 ≈ 2.4 (moyennes empiriques tennis).
  const expSets = gamesOU.best_of === 5 ? 3.6 : 2.4;
  const mk = parseFloat((meanSet * expSets).toFixed(2));
  const diff = parseFloat((exp - mk).toFixed(2));
  const agree = Math.abs(diff) <= 2.0;
  return { bsd_expected: exp, markov_ref: mk, diff, agree,
    conviction: agree ? 'high' : (Math.abs(diff) <= 4 ? 'medium' : 'low') };
}

// ── SPRINT 1 — Serve Dominance Index (SDI) via matchmx TA déjà caché ─────────
// Réutilise les rows KoA (tennis_koa_matchmx, scrape player-classic.cgi déjà
// en place, queue concurrence 2). ZÉRO scraping neuf. Bloc service = vainqueur
// si row[4]='W' sinon perdant (+9). Indices TENNIS_KOA_W / TENNIS_KOA_L.
function computeServeDominance(rows, surface, lastN = 30) {
  if (!Array.isArray(rows) || !rows.length) return null;
  const surf = (surface && surface !== 'ALL') ? String(surface).toLowerCase() : null;
  let svpt = 0, ptsWon = 0, ace = 0, n = 0;
  for (const x of rows) {
    if (n >= lastN) break;
    if (!Array.isArray(x)) continue;
    const wl = String(x[4] == null ? '' : x[4]).trim();
    if (wl !== 'W' && wl !== 'L') continue;
    if (surf) {
      const sc = String(x[2] == null ? '' : x[2]).trim().toLowerCase();
      if (sc && sc !== surf) continue;
    }
    const o = wl === 'W' ? TENNIS_KOA_W : TENNIS_KOA_L;
    const sp = Number(x[o.svpt]), f1 = Number(x[o.f1w]), f2 = Number(x[o.f2w]), a = Number(x[o.ace]);
    if (!Number.isFinite(sp) || sp <= 0) continue;
    svpt += sp; ptsWon += (Number.isFinite(f1) ? f1 : 0) + (Number.isFinite(f2) ? f2 : 0);
    ace += Number.isFinite(a) ? a : 0; n++;
  }
  if (n < 5 || svpt <= 0) return null;
  const spw = (ptsWon / svpt) * 100;
  const acePct = (ace / svpt) * 100;
  // SDI 0-100 : points gagnés au service (cœur du hold) + bonus aces gratuits.
  const sdi = Math.max(0, Math.min(100, spw + 0.30 * acePct));
  return {
    sdi: parseFloat(sdi.toFixed(1)),
    serve_pts_won_pct: parseFloat(spw.toFixed(1)),
    ace_pct: parseFloat(acePct.toFixed(1)),
    sample: n,
  };
}

// [FIX diacritiques] Mappe un nom accenté (BSD) vers le nom EXACT stocké dans
// tennis_matches (ASCII Sackmann), via match accent-insensible (fn unaccent).
// Une fois canonicalisé, TOUS les lookups (Elo/Markov/KoA/fatigue/logdiff)
// matchent. Cache pour éviter la requête par-match.
const _canonNameCache = new Map();
function _canonTennisName(name, tour) {
  if (!name || !tour) return null;
  const ck = tour + '|' + name.toLowerCase();
  if (_canonNameCache.has(ck)) return _canonNameCache.get(ck);
  let out = null;
  try {
    const r = sqldb.prepare(`
      SELECT n FROM (
        SELECT winner_name AS n FROM tennis_matches
          WHERE tour=? AND unaccent(LOWER(winner_name))=unaccent(LOWER(?))
        UNION ALL
        SELECT loser_name AS n FROM tennis_matches
          WHERE tour=? AND unaccent(LOWER(loser_name))=unaccent(LOWER(?))
      ) LIMIT 1
    `).get(tour, name, tour, name);
    if (r && r.n) out = r.n;
  } catch (_) { out = null; }
  _canonNameCache.set(ck, out);
  return out;
}

async function _buildTennisValueBetsCore({ date }) {
  const dateClean = date ? String(date).replace(/[^0-9-]/g, '').slice(0, 10) : '';
  let bsdMatches = [];
  let matchSource = 'bsd';

  if (BSD_TENNIS_ENABLED) {
    const suffix = dateClean
      ? `/api/v2/matches/?date=${encodeURIComponent(dateClean)}&status=scheduled&limit=200`
      : `/api/v2/matches/?status=scheduled&limit=200`;
    const ck = `bsd_tennis_value_bets_${dateClean || 'today'}`;
    const bsd = await handleTennisBSD(suffix, ck, 30 * 60 * 1000);
    if (bsd.status === 200) {
      bsdMatches = _extractBsdMatchesList(bsd.body);
      if (!bsdMatches.length) console.warn('  [TennisVB] BSD list HTTP 200 mais 0 match scheduled → fallback ESPN (slate vide ?)');
    } else if (bsd.status !== 503 && bsd.status !== 402) {
      // Vraie erreur upstream BSD (5xx) → propager.
      return { status: bsd.status, body: bsd.body };
    } else {
      console.warn(`  [TennisVB] fallback ESPN — BSD scheduled list status=${bsd.status} (${bsd.status === 402 ? 'addon requis' : 'indisponible'}) → ids ESPN, detail BSD KO ce cycle`);
    }
    // 402/503 → tombe en fallback ESPN ci-dessous (mode dégradé).
  }

  if (bsdMatches.length === 0) {
    // Fallback ESPN : live scoreboard (scores à jour) + schedule J→J+N (option C,
    // fait remonter les programmés). Merge dédup, live prioritaire sur programmé.
    if (Date.now() - _tennisLiveCache.ts > TENNIS_LIVE_TTL_MS) {
      try { await pollTennisLive(); } catch (e) { /* swallow */ }
    }
    const liveRaw = Array.isArray(_tennisLiveCache.data) ? _tennisLiveCache.data : [];
    let schedRaw = [];
    try { schedRaw = await getTennisScheduleCached(); } catch (e) { /* swallow */ }
    const _mById = new Map();
    for (const m of schedRaw) if (m && m.id) _mById.set(m.id, m);
    for (const m of liveRaw) if (m && m.id) _mById.set(m.id, m); // live écrase programmé
    const espnRaw = _mById.size ? Array.from(_mById.values()) : liveRaw;
    // Mappe au schéma attendu par la boucle d'enrichissement ci-dessous.
    // ESPN ne fournit pas la surface réelle (Hard/Clay/Grass) — sera enrichi par Sackmann (T3+T4).
    bsdMatches = espnRaw.map(m => ({
      id: m.id,
      tournament: m.tournament || null,
      surface: null,
      court: m.court || null,
      tour: m.tour || null,
      round: m.round || null,
      start_time: m.start_time || null,
      status: m.status || null,
      player1: { name: m.player1 && m.player1.name, country: m.player1 && m.player1.country, flag: m.player1 && m.player1.flag },
      player2: { name: m.player2 && m.player2.name, country: m.player2 && m.player2.country, flag: m.player2 && m.player2.flag },
    }));
    matchSource = 'espn';
  }

  // Force refresh odds cache si stale (await pour que les odds soient prêts pour cette requête)
  if (Date.now() - _tennisOddsCache.ts > TENNIS_ODDS_TTL_MS) {
    try { await fetchTennisOddsAPI(); } catch (e) { /* swallow */ }
  }

  // [FIX bug onglet tennis — v2] ZÉRO fetch BSD sur le chemin requête. Le cold
  // build (302 matchs + Markov/TA) + les fetchs paginés faisaient dépasser le
  // timeout client → "Erreur réseau". On lit UNIQUEMENT les caches déjà chauds
  // (synchrone, instantané). Un warmer background (fin de pollTennisLive, 30s)
  // remplit ces caches. Cold = signaux null → tableau s'affiche vite ;
  // build suivant (cache chaud) = enrichi.
  let predMap = new Map(), calib = null, rankIdx = new Map();
  try {
    const _pc = apiCacheGet(`bsd_tennis_preds_${dateClean || 'upcoming'}`);
    if (_pc) predMap = _predListToMap(_pc);
  } catch (e) { /* pas de pred chaude */ }
  try {
    if (_bsdTennisCalib && _bsdTennisCalib.data && Date.now() - _bsdTennisCalib.ts < 6 * 3600 * 1000) calib = _bsdTennisCalib.data;
  } catch (e) { /* pas de calib chaude */ }
  try {
    if (_bsdTennisRank && _bsdTennisRank.byKey && Date.now() - _bsdTennisRank.ts < 6 * 3600 * 1000) rankIdx = _bsdTennisRank.byKey;
  } catch (e) { /* pas de rank chaud */ }

  const enriched = [];
  const _vbT0 = Date.now();
  let _vbI = 0;
  console.log(`  [TennisVB] build start — ${bsdMatches.length} matchs (src=${matchSource})`);
  for (const m of bsdMatches) {
    // Yield event-loop tous les 20 matchs : la boucle CPU bloquait le process
    // ~20s (autres routes/SSE gelées) et empêchait tout timeout de tirer.
    if (++_vbI % 20 === 0) await new Promise(r => setImmediate(r));
    let p1Name = (m.player1 && (m.player1.name || m.player1.full_name)) || m.player1_name || '';
    let p2Name = (m.player2 && (m.player2.name || m.player2.full_name)) || m.player2_name || '';
    // [FIX CRASH render] BSD renvoie tournament = OBJET {id,name,…} ; ESPN =
    // string. Le frontend faisait `tournament.localeCompare` → throw → render
    // KO → table figée "Chargement…" en boucle. On NORMALISE en string ici.
    const _tName = (m.tournament && typeof m.tournament === 'object')
      ? (m.tournament.name || m.tournament.short_name || m.tournament.short || null)
      : (m.tournament || null);
    if (!p1Name || !p2Name) {
      enriched.push({
        id: m.id,
        tournament: _tName,
        surface: m.surface || null,
        round: m.round || null,
        start_time: m.start_time || m.commence_time || null,
        status: m.status || null,
        player1: m.player1 || { name: p1Name || null },
        player2: m.player2 || { name: p2Name || null },
        odds: null, fair: null, edge: null, best_edge: null,
        bsd_prediction: m.prediction || null,
        bsd_ml_score: m.ml_score || m.prediction_score || null,
        sources: { match: matchSource, odds: null },
      });
      continue;
    }

    let odds = null, fair = null, edge = null, bestEdge = null, oddsSource = null;
    const found = findTennisOddsForPlayers(p1Name, p2Name);
    if (found) {
      const raw = extractBestTennisH2H(found.match);
      if (raw) {
        // Réoriente p1/p2 selon l'ordre BSD (Odds API peut inverser home/away).
        const p1Odds = found.swapped ? raw.p2.odds : raw.p1.odds;
        const p2Odds = found.swapped ? raw.p1.odds : raw.p2.odds;
        const p1Book = found.swapped ? raw.p2.book : raw.p1.book;
        const p2Book = found.swapped ? raw.p1.book : raw.p2.book;

        odds = { p1: { odds: p1Odds, book: p1Book }, p2: { odds: p2Odds, book: p2Book } };
        const dev = devig2way(p1Odds, p2Odds, 'shin');
        if (dev) {
          const evP1 = (p1Odds * dev.p1 - 1) * 100;
          const evP2 = (p2Odds * dev.p2 - 1) * 100;
          fair = {
            p1: parseFloat((dev.p1 * 100).toFixed(2)),
            p2: parseFloat((dev.p2 * 100).toFixed(2)),
            margin: dev.margin,
            method: dev.method,
          };
          edge = {
            p1: parseFloat(evP1.toFixed(2)),
            p2: parseFloat(evP2.toFixed(2)),
          };
          bestEdge = evP1 >= evP2
            ? { side: 'p1', player: p1Name, odds: p1Odds, book: p1Book, edge: edge.p1 }
            : { side: 'p2', player: p2Name, odds: p2Odds, book: p2Book, edge: edge.p2 };
        }
        oddsSource = 'theoddsapi';
      }
    }

    // ── T5 : Predictions Elo + BSD blend + EV model ────────────────────────
    // [FIX enrichissement vide] BSD = imbriqué (m.tournament.circuit/.surface,
    // m.tournament=objet) ; ESPN = plat (m.tour/m.surface string). L'ancien code
    // lisait UNIQUEMENT la forme ESPN → tourGuess null pour TOUS les matchs BSD
    // → zéro Elo/Markov/KoA/Jeux (table "—" même sur ATP). On normalise les 2.
    const _tObj = (m.tournament && typeof m.tournament === 'object') ? m.tournament : null;
    const _tourN = m.tour || (_tObj && _tObj.circuit) || '';
    const _surfN = m.surface || (_tObj && _tObj.surface) || null;
    const tourGuess = ['ATP', 'WTA'].includes(String(_tourN).toUpperCase()) ? String(_tourN).toUpperCase() : null;
    // Canonicalise les noms (accent-insensible) → nom ASCII stocké Sackmann/Elo.
    // Tous les lookups en aval (Elo/Markov/KoA/fatigue/logdiff) matchent ensuite.
    if (tourGuess) {
      p1Name = _canonTennisName(p1Name, tourGuess) || p1Name;
      p2Name = _canonTennisName(p2Name, tourGuess) || p2Name;
    }
    let surfaceClean = (_surfN && TENNIS_ELO_SURFACES.includes(String(_surfN).toLowerCase())) ? String(_surfN).toLowerCase() : null;
    let surfaceSource = surfaceClean ? matchSource : null;
    if (!surfaceClean && _tName) {
      const resolved = resolveTennisSurfaceSync(_tName); // sync, zéro scrape (FIX timeout)
      if (resolved && TENNIS_ELO_SURFACES.includes(resolved.surface)) {
        surfaceClean = resolved.surface;
        surfaceSource = resolved.source;
      }
    }
    let eloProb = null;
    let setProbs = null;
    let setModel = null;
    const _surfSpeed = getTennisSurfaceSpeed(_tName);
    if (tourGuess) {
      eloProb = _tennisLookupEloPair(p1Name, p2Name, tourGuess, surfaceClean);
      // ── P1-1 : Markov serve/return v2 + marchés dérivés jeux ───────────
      setProbs = computeTennisMarkovSetProbs(p1Name, p2Name, tourGuess, surfaceClean, _surfSpeed);
      // ── set_profile_v1 : modèle 1er/2e set (profils + transition + fatigue) ─
      setModel = computeTennisSetModel(p1Name, p2Name, tourGuess, surfaceClean, setProbs);
    }
    // ── at_least_one_set : Markov set_probs × split empirique TA/Sackmann ────
    let atLeastOneSet = null;
    if (tourGuess && setProbs) {
      const _surfKey = surfaceClean || 'ALL';
      const _taP1 = getTaOverlayCached(p1Name, tourGuess, _surfKey);
      const _taP2 = getTaOverlayCached(p2Name, tourGuess, _surfKey);
      const _splitP1 = _taP1 || computeSweepSplitLocal(p1Name, tourGuess, _surfKey);
      const _splitP2 = _taP2 || computeSweepSplitLocal(p2Name, tourGuess, _surfKey);
      atLeastOneSet = computeAtLeastOneSet(setProbs, _tennisBestOf(tourGuess, _tName), _splitP1, _splitP2);
      // Rafraîchit le scrape TA en arrière-plan (best-effort, ne bloque pas le rendu).
      if (!_taP1 || _taP1.stale) fetchTennisAbstractPlayer(p1Name, tourGuess, _surfKey).catch(() => {});
      if (!_taP2 || _taP2.stale) fetchTennisAbstractPlayer(p2Name, tourGuess, _surfKey).catch(() => {});
    }
    // ── most_aces : King of Aces — Tennis Abstract matchmx (frais, no fallback) ─
    let mostAces = null;
    let serveDom = null;
    if (tourGuess) {
      const _koaSurf = surfaceClean || 'ALL';
      const _koaC1 = getKoaMatchmxCached(p1Name, tourGuess);
      const _koaC2 = getKoaMatchmxCached(p2Name, tourGuess);
      if (_koaC1 && _koaC2) {
        mostAces = computeMostAcesMatchup(p1Name, p2Name, tourGuess, _koaSurf, _koaC1.rows, _koaC2.rows);
        // SDI : même rows matchmx (zéro fetch). Gardé : ne doit pas 500 le build.
        try {
          let sd1 = computeServeDominance(_koaC1.rows, surfaceClean);
          let sd2 = computeServeDominance(_koaC2.rows, surfaceClean);
          if (!sd1) sd1 = computeServeDominance(_koaC1.rows, 'ALL');
          if (!sd2) sd2 = computeServeDominance(_koaC2.rows, 'ALL');
          if (sd1 && sd2) serveDom = { p1: sd1, p2: sd2, delta: parseFloat((sd1.sdi - sd2.sdi).toFixed(1)) };
        } catch (e) { /* SDI omis pour ce match */ }
      }
      if (!_koaC1 || _koaC1.stale) _koaEnqueue(p1Name, tourGuess);
      if (!_koaC2 || _koaC2.stale) _koaEnqueue(p2Name, tourGuess);
    }
    // ── games_pmf_dp_v1 : O/U jeux par set (S1-S3 + S4/S5 si Grand Chelem) ───
    let gamesOU = null;
    if (tourGuess && setProbs && Number.isFinite(setProbs.p1_hold) && Number.isFinite(setProbs.p2_hold)) {
      const _aceP1 = computePlayerAceRate(p1Name, tourGuess, surfaceClean || 'ALL');
      const _aceP2 = computePlayerAceRate(p2Name, tourGuess, surfaceClean || 'ALL');
      gamesOU = computeTennisGamesOverUnder({
        p1Hold: setProbs.p1_hold,
        p2Hold: setProbs.p2_hold,
        tournament: _tName,
        tour: tourGuess,
        surface: surfaceClean,
        setModel,
        aceP1: _aceP1 ? _aceP1.ace_pct : null,
        aceP2: _aceP2 ? _aceP2.ace_pct : null,
      });
    }
    // Prédiction ML BSD via Map bulk (clé id match ou paire joueurs) — plus de null.
    let bsdProb = null, bsdPred = null;
    const _pred = predMap.get('id:' + m.id) || predMap.get('pk:' + _tnNameKey(p1Name, p2Name));
    if (_pred) {
      const a = parseFloat(_pred.prob_player1_wins), b = parseFloat(_pred.prob_player2_wins);
      if (Number.isFinite(a) && Number.isFinite(b) && (a + b) > 0) {
        bsdProb = { p1: a / 100, p2: b / 100 };
      }
      bsdPred = {
        predicted_winner: _pred.predicted_winner ?? null,
        confidence: _pred.confidence ?? null,
        expected_total_sets: _pred.expected_total_sets ?? null,
        prob_over_2_5_sets: _pred.prob_over_2_5_sets ?? null,
        expected_total_games: _pred.expected_total_games ?? null,
        prob_over_20_5_games: _pred.prob_over_20_5_games ?? null,
        prob_over_21_5_games: _pred.prob_over_21_5_games ?? null,
        prob_over_22_5_games: _pred.prob_over_22_5_games ?? null,
        prob_player1_wins_first_set: _pred.prob_player1_wins_first_set ?? null,
      };
    }
    // Sprint 2 — blend dynamique : poids BSD ∝ fiabilité calibrée mesurée.
    const _rel = _calibReliability(calib, bsdPred && bsdPred.confidence, surfaceClean);
    const _wBsd = _rel != null ? parseFloat((0.20 + 0.50 * _rel).toFixed(3)) : null;
    const blended = blendTennisProbsW(eloProb, bsdProb, _wBsd);

    // ── Sprint 1 dérivés (gardé : un throw ne doit jamais 500 le tableau) ────
    let _confBadge = null, _mlMktDiv = null, _rkP1 = null, _rkP2 = null;
    try {
      _confBadge = _calibBadge(calib, bsdPred && bsdPred.confidence, surfaceClean);
      if (bsdProb && fair && fair.p1 != null) {
        const d1 = parseFloat((bsdProb.p1 * 100 - fair.p1).toFixed(2));
        _mlMktDiv = { p1: d1, p2: parseFloat((bsdProb.p2 * 100 - fair.p2).toFixed(2)), flag: Math.abs(d1) >= 8 };
      }
      _rkP1 = _rankMomentum(rankIdx.get(normName(p1Name)));
      _rkP2 = _rankMomentum(rankIdx.get(normName(p2Name)));
    } catch (e) { /* signaux S1 omis pour ce match — build continue */ }

    // Confiance calibrée PAR MARCHÉ totaux (sets/jeux) — accuracy réelle mesurée
    // via was_over_*_correct. Consommée par computeTennisPredictiveBets pour ne
    // plus appliquer la confiance vainqueur aux paris sets/jeux (G1+G2).
    let _mktConf = null;
    try {
      if (calib && calib.by_market) {
        const mk = (key) => {
          const m = calib.by_market[key];
          if (!m || m.acc == null || m.n < 20) return null;
          return { acc: parseFloat((m.acc * 100).toFixed(1)), n: m.n,
            ci_low: parseFloat((m.low * 100).toFixed(1)), rel: _calibMarketRel(calib, key) };
        };
        const os = mk('over_sets'), og = mk('over_games');
        if (os || og) _mktConf = { over_sets: os, over_games: og };
      }
    } catch (e) { /* calib marché absente — décote prudente côté predictive */ }

    let evModel = null, bestEvModel = null;
    if (blended && odds && odds.p1 && odds.p2) {
      const evP1 = (odds.p1.odds * blended.p1 - 1) * 100;
      const evP2 = (odds.p2.odds * blended.p2 - 1) * 100;
      evModel = {
        p1: parseFloat(evP1.toFixed(2)),
        p2: parseFloat(evP2.toFixed(2)),
      };
      bestEvModel = evP1 >= evP2
        ? { side: 'p1', player: p1Name, odds: odds.p1.odds, book: odds.p1.book, ev: evModel.p1, p_model: blended.p1 }
        : { side: 'p2', player: p2Name, odds: odds.p2.odds, book: odds.p2.book, ev: evModel.p2, p_model: blended.p2 };
    }

    // ── Sprint 2 dérivés (gardé idem) ───────────────────────────────────────
    let _trap = null, _confEdge = null, _firstSet = null, _totConv = null;
    try {
      _trap = _computeTrapBet(fair, blended, _confBadge, bestEvModel);
      if (bestEvModel && _rel != null) {
        const v = parseFloat((bestEvModel.ev * _rel).toFixed(2));
        _confEdge = { value: v, reliability: _rel, actionable: (bestEvModel.ev > 0 && _rel >= 0.30 && v >= 2) };
      }
      if (bsdPred && bsdPred.prob_player1_wins_first_set != null) {
        const fs1 = Number(bsdPred.prob_player1_wins_first_set);
        const mp1 = blended ? blended.p1 * 100 : null;
        _firstSet = {
          p1_pct: parseFloat(fs1.toFixed(1)),
          lean: fs1 >= 55 ? 'p1' : fs1 <= 45 ? 'p2' : 'even',
          diverges_match: mp1 != null ? (Math.abs(fs1 - mp1) >= 10) : null,
        };
      }
      _totConv = _computeTotalsConvergence(bsdPred, gamesOU);
    } catch (e) { /* signaux S2 omis pour ce match — build continue */ }

    let _p1ss = { rk: null, total: null, form: [], l5_pts: null, l10_pts: null, powerscore: null, ps_rank: null, ps_total: null };
    let _p2ss = { rk: null, total: null, form: [], l5_pts: null, l10_pts: null, powerscore: null, ps_rank: null, ps_total: null };
    if (tourGuess && surfaceClean) {
      try {
        _p1ss = getTennisSurfStats(p1Name, tourGuess, surfaceClean);
        _p2ss = getTennisSurfStats(p2Name, tourGuess, surfaceClean);
      } catch (_) { /* surf stats absents — colonne 2 affichera N/A */ }
    }

    enriched.push({
      id: m.id,
      tournament: _tName,
      surface: surfaceClean || _surfN || null,
      surface_source: surfaceSource,
      court: m.court || null,
      tour: tourGuess || _tourN || null,
      round: m.round || null,
      start_time: m.start_time || m.commence_time || null,
      status: m.status || null,
      player1: Object.assign({ name: p1Name }, m.player1 || {}, { surf_rank: _p1ss.rk, surf_rank_total: _p1ss.total, surf_form: _p1ss.form, l5_pts: _p1ss.l5_pts, l10_pts: _p1ss.l10_pts, powerscore: _p1ss.powerscore, ps_rank: _p1ss.ps_rank, ps_total: _p1ss.ps_total }),
      player2: Object.assign({ name: p2Name }, m.player2 || {}, { surf_rank: _p2ss.rk, surf_rank_total: _p2ss.total, surf_form: _p2ss.form, l5_pts: _p2ss.l5_pts, l10_pts: _p2ss.l10_pts, powerscore: _p2ss.powerscore, ps_rank: _p2ss.ps_rank, ps_total: _p2ss.ps_total }),
      odds,
      fair,
      edge,
      best_edge: bestEdge,
      bsd_prediction: m.prediction || null,
      bsd_ml_score: m.ml_score || m.prediction_score || null,
      bsd_markets: bsdPred,
      market_confidence: _mktConf,
      confidence_badge: _confBadge,
      ml_market_div: _mlMktDiv,
      rank_momentum: { p1: _rkP1, p2: _rkP2 },
      serve_dominance: serveDom,
      trap_bet: _trap,
      conf_edge: _confEdge,
      first_set: _firstSet,
      totals_convergence: _totConv,
      predictions: {
        elo: eloProb,
        bsd: bsdProb,
        blended,
        set_probs: setProbs,
        at_least_one_set: atLeastOneSet,
        most_aces: mostAces,
      },
      log_diff: tourGuess ? {
        p1: tennisLogDiff(p1Name, tourGuess),
        p2: tennisLogDiff(p2Name, tourGuess),
      } : null,
      surface_speed: getTennisSurfaceSpeed(_tName),
      fatigue: tourGuess ? {
        p1: computePlayerFatigue(p1Name, tourGuess),
        p2: computePlayerFatigue(p2Name, tourGuess),
      } : null,
      set_model: setModel,
      over_under_set_calculations: gamesOU,
      ev_model: evModel,
      best_ev_model: bestEvModel,
      sources: { match: matchSource, odds: oddsSource, predictions: (eloProb && bsdProb) ? 'elo+bsd' : (eloProb ? 'elo' : (bsdProb ? 'bsd' : null)) },
    });
  }

  // Snapshot serveur : conserve chaque match enrichi en mémoire (par id BSD +
  // paires de noms multi-tokens) pour pouvoir le ré-injecter quand BSD le
  // drop de la liste scheduled lors du passage in_progress.
  let _snapStored = 0;
  for (const _e of enriched) {
    try { _tnSrvStoreSnap(_e); _snapStored++; } catch (_) { /* snap non bloquant */ }
  }

  // Recall live-only : pour chaque match du live cache absent de enriched,
  // tente une réhydratation depuis le snapshot persistant. Si trouvé, clone
  // l'enrichissement + merge le bloc _live → push. Garantit zéro colonne vide
  // sur transition prematch→live, indépendamment du bootstrap navigateur.
  const _liveRaw = Array.isArray(_tennisLiveCache.data) ? _tennisLiveCache.data : [];
  const _presentIds = new Set();
  const _presentPairs = new Set();
  for (const _e of enriched) {
    if (_e.id != null) _presentIds.add(String(_e.id));
    const _pk = _tnSrvPairKey(_e.player1 && _e.player1.name, _e.player2 && _e.player2.name);
    if (_pk) _presentPairs.add(_pk);
  }
  let _rehydratedLive = 0, _liveOrphans = 0;
  for (const lo of _liveRaw) {
    if (!lo || lo.is_live !== true) continue;
    if (lo.id != null && _presentIds.has(String(lo.id))) continue;
    const _lpk = _tnSrvPairKey(lo.player1 && lo.player1.name, lo.player2 && lo.player2.name);
    if (_lpk && _presentPairs.has(_lpk)) continue;
    const snap = _tnSrvLookupSnap(lo);
    if (!snap) { _liveOrphans++; continue; }
    let rehydrated;
    try { rehydrated = JSON.parse(JSON.stringify(snap)); } catch (_) { continue; }
    rehydrated.status = lo.status || 'LIVE';
    rehydrated._live = lo;
    rehydrated._isLive = true;
    rehydrated._rehydrated_source = 'server_snap';
    enriched.push(rehydrated);
    _rehydratedLive++;
  }

  for (const _e of enriched) { try { _e.predictive = computeTennisPredictiveBets(_e); } catch (_) { _e.predictive = null; } }
  console.log(`  [TennisVB] build done — ${enriched.length} matchs en ${Date.now() - _vbT0}ms · snap_stored=${_snapStored} · live_rehydrated=${_rehydratedLive} · live_orphans=${_liveOrphans} · snap_map_size=${_tennisEnrichSnap.size}`);
  return {
    status: 200,
    body: {
      count: enriched.length,
      matches: enriched,
      meta: {
        match_source: matchSource,
        degraded: matchSource !== 'bsd',
        odds_sports_active: _activeTennisSports,
        odds_cache_age_s: _tennisOddsCache.ts ? Math.floor((Date.now() - _tennisOddsCache.ts) / 1000) : null,
        bsd_enabled: BSD_TENNIS_ENABLED,
        odds_api_enabled: !!ODDS_API_KEY,
        devig_method: 'shin-hurley',
        bsd_calibration: calib ? { n: calib.n, accuracy: calib.accuracy, brier: calib.brier } : null,
        built_ts: Date.now(),
        snap_stored: _snapStored,
        live_rehydrated: _rehydratedLive,
        live_orphans: _liveOrphans,
        snap_map_size: _tennisEnrichSnap.size,
      },
    },
  };
}

// ─── P0-1 — Objet tennisMatch canonique (miroir de l'objet match football) ──
// Aplatit l'objet enrichi buildTennisValueBets en un schéma stable et
// table-friendly consommé par l'onglet Tennis consolidé (P0-2).
function _tennisConfidence(eloProb) {
  if (!eloProb) return { tier: 'none', score: 0 };
  const mn = Math.min(eloProb.p1_matches || 0, eloProb.p2_matches || 0);
  if (mn >= 40) return { tier: 'high', score: 90 };
  if (mn >= 15) return { tier: 'medium', score: 65 };
  if (mn >= 5) return { tier: 'low', score: 40 };
  return { tier: 'sparse', score: 20 };
}

// ─── Bets Prédictifs Tennis — moteur PredScore composite ────────────────────
// Évalue un pool de marchés candidats à partir des signaux DÉJÀ calculés par
// buildTennisValueBets (Elo surface, BSD ML, blended, set_probs, Markov
// Sackmann, set_model, most_aces, O/U jeux, EV/edge, confidence_badge) puis
// sort le top 3 + un verdict KPI directif. Aucune nouvelle source réseau.
//   PredScore = 0.45·norm(EV%) + 0.35·Confiance + 0.20·Accord(Elo,BSD)
//   sans cote :  0.55·proba + 0.45·Confiance
function _tnPct(x) {
  if (x == null || !Number.isFinite(Number(x))) return null;
  const v = Number(x);
  return v <= 1 ? Math.round(v * 1000) / 10 : Math.round(v * 10) / 10;
}
function computeTennisPredictiveBets(e) {
  try {
    const P = _tnPct;
    const pr = e.predictions || {};
    const blended = pr.blended || pr.elo || null;
    const elo = pr.elo || null, bsd = pr.bsd || null;
    const conf = e.confidence_badge || null;
    const div = e.ml_market_div || null;
    const odds = e.odds || {};
    const sm = e.set_model || {};
    const n1 = (e.player1 && e.player1.name) || 'J1';
    const n2 = (e.player2 && e.player2.name) || 'J2';
    const bsdM = e.bsd_markets || null;        // prédictions ML natives BSD
    const mktC = e.market_confidence || null;  // fiabilité réelle par marché totaux

    // Confiance 0..1 — calibration modèle, pénalité divergence + échantillon
    let C = conf && Number.isFinite(conf.accuracy) ? Math.max(0, Math.min(1, conf.accuracy / 100)) : 0.5;
    if (div === 'HIGH') C *= 0.8;
    const samp = conf && Number.isFinite(conf.sample) ? conf.sample : null;
    if (samp != null) { if (samp < 5) C *= 0.6; else if (samp < 15) C *= 0.8; }
    // Accord Elo vs BSD ML (convergence des deux modèles)
    let agree = 0.5;
    if (elo && bsd) {
      const e1 = P(elo.p1), b1 = P(bsd.p1);
      if (e1 != null && b1 != null) agree = Math.max(0, 1 - Math.abs(e1 - b1) / 100);
    }

    const cands = [];
    // cOv : override confiance ∈[0,1] propre au marché (calibration sets/jeux
    // mesurée). Absent → C vainqueur. Évite d'appliquer la fiabilité du
    // modèle vainqueur à un pari totaux dont l'accuracy réelle diffère.
    const push = (mkt, label, side, prob, dec, book, cOv) => {
      const p = P(prob);
      if (p == null || p <= 0) return;
      const Cx = (cOv != null && Number.isFinite(cOv)) ? Math.max(0, Math.min(1, cOv)) : C;
      let ev = null;
      if (dec && Number.isFinite(dec) && dec > 1) ev = Math.round((p / 100 * dec - 1) * 1000) / 10;
      const evN = ev != null ? Math.max(0, Math.min(1, ev / 20)) : null;
      const score = ev != null
        ? 0.45 * evN + 0.35 * Cx + 0.20 * agree
        : 0.55 * (p / 100) + 0.45 * Cx;
      const hasMkt = (dec && dec > 1);
      cands.push({ mkt, label, side: side || null, prob: p,
        odds: hasMkt ? Math.round(dec * 100) / 100 : null,
        odds_fair: p > 0 ? Math.round((100 / p) * 100) / 100 : null,
        odds_type: hasMkt ? 'market' : 'fair',
        book: book || null, ev, score: Math.round(score * 1000) / 1000 });
    };

    // 1 — Vainqueur match (cote marché → EV réel)
    if (blended) {
      const p1 = P(blended.p1), p2 = P(blended.p2);
      if (p1 != null && p2 != null) {
        const s1 = p1 >= p2;
        push('ML', (s1 ? n1 : n2) + ' vainqueur', s1 ? 'p1' : 'p2', s1 ? p1 : p2,
          s1 ? (odds.p1 && odds.p1.odds) : (odds.p2 && odds.p2.odds),
          s1 ? (odds.p1 && odds.p1.book) : (odds.p2 && odds.p2.book));
      }
    }
    // 2 — Vainqueur Set 1 — prédiction ML BSD native prioritaire (sinon Markov
    // local set_model). 1er set non couvert par les flags réglés Bzzoiro
    // (winner/sets/games seuls) → confiance décotée 0.7·C (non mesurée).
    {
      let s1p = (bsdM && bsdM.prob_player1_wins_first_set != null) ? P(bsdM.prob_player1_wins_first_set) : null;
      const fromBsd = s1p != null;
      if (s1p == null && sm.set1 && sm.set1.p1_pct != null) s1p = P(sm.set1.p1_pct);
      if (s1p != null) {
        const s1 = s1p >= 50;
        push('SET1', (s1 ? n1 : n2) + ' gagne Set 1' + (fromBsd ? ' (ML)' : ''),
          s1 ? 'p1' : 'p2', s1 ? s1p : 100 - s1p, null, null, fromBsd ? C * 0.7 : null);
      }
    }
    // 3 — Score sets exact (issue best-of-3 la + probable)
    if (Array.isArray(pr.set_probs) && pr.set_probs.length) {
      let best = null;
      for (const sp of pr.set_probs) {
        const a = P(sp.p1) || 0, b = P(sp.p2) || 0;
        const side = a >= b ? 'p1' : 'p2', val = Math.max(a, b);
        if (!best || val > best.val) best = { val, side, out: sp.outcome };
      }
      if (best && best.val > 0) push('SETEXACT', 'Score ' + best.out + ' (' + (best.side === 'p1' ? n1 : n2) + ')', best.side, best.val, null, null);
    }
    // 4 — Gagne ≥1 set (value outsider — Markov Sackmann)
    if (pr.at_least_one_set && blended) {
      const p1 = P(blended.p1), p2 = P(blended.p2);
      const out = (p1 != null && p2 != null && p1 < p2) ? 'p1' : 'p2';
      const v = P(out === 'p1' ? pr.at_least_one_set.p1 : pr.at_least_one_set.p2);
      if (v != null && v >= 55) push('SET1PLUS', (out === 'p1' ? n1 : n2) + ' gagne ≥1 set', out, v, null, null);
    }
    // 5 — Total jeux O/U — prédiction ML BSD native prioritaire (lignes 20.5 /
    // 21.5 / 22.5), confiance = fiabilité RÉELLE marché over_games mesurée
    // (was_over_games_correct) ; décote 0.7·C si calib indisponible. Sinon
    // fallback Markov local over_under_set_calculations.
    {
      let pushed = false;
      if (bsdM) {
        const lines = [['prob_over_20_5_games', 20.5], ['prob_over_21_5_games', 21.5], ['prob_over_22_5_games', 22.5]];
        let bestG = null;
        for (const [k, ln] of lines) {
          const ov = P(bsdM[k]);
          if (ov == null) continue;
          const over = { v: ov, lbl: '+' + ln + ' jeux (ML)' };
          const under = { v: 100 - ov, lbl: '-' + ln + ' jeux (ML)' };
          for (const c of [over, under]) if (!bestG || c.v > bestG.v) bestG = c;
        }
        if (bestG && bestG.v >= 55) {
          const cOv = (mktC && mktC.over_games && mktC.over_games.rel != null) ? mktC.over_games.rel : C * 0.7;
          push('GAMES', 'Total ' + bestG.lbl, null, bestG.v, null, null, cOv);
          pushed = true;
        }
      }
      if (!pushed) {
        const gou = e.over_under_set_calculations || {};
        const map = [['O7_5', '+7.5 jeux'], ['O8_5', '+8.5 jeux'], ['O9_5', '+9.5 jeux'], ['U12_5', '-12.5 jeux']];
        let bestG = null;
        for (const [k, lbl] of map) { const v = P(gou[k]); if (v != null && (!bestG || v > bestG.v)) bestG = { v, lbl }; }
        if (bestG && bestG.v >= 55) push('GAMES', 'Total ' + bestG.lbl, null, bestG.v, null, null);
      }
    }
    // 5b — Total sets O/U 2.5 — ML BSD natif, confiance = fiabilité réelle
    // marché over_sets mesurée (was_over_sets_correct) ; décote 0.7·C sinon.
    if (bsdM && bsdM.prob_over_2_5_sets != null) {
      const ov = P(bsdM.prob_over_2_5_sets);
      if (ov != null) {
        const over = ov >= 50;
        const v = over ? ov : 100 - ov;
        if (v >= 55) {
          const cOv = (mktC && mktC.over_sets && mktC.over_sets.rel != null) ? mktC.over_sets.rel : C * 0.7;
          push('SETS', 'Total ' + (over ? '+2.5' : '-2.5') + ' sets (ML)', null, v, null, null, cOv);
        }
      }
    }
    // 6 — King of Aces
    if (pr.most_aces && pr.most_aces.favorite && pr.most_aces.pct != null) {
      const fav = pr.most_aces.favorite === 'J1' ? 'p1' : 'p2';
      const v = P(pr.most_aces.pct);
      if (v != null && v >= 55) push('ACES', (fav === 'p1' ? n1 : n2) + " + d'aces", fav, v, null, null);
    }

    cands.sort((a, b) => b.score - a.score);
    const top = cands.slice(0, 3);

    // Verdict KPI directif — règle stricte CLAUDE.md (EV>5 ET IC bas>0 ET vert)
    let verdict = 'PASS', tone = 'pass';
    const strong = cands.some(b => b.ev != null && b.ev > 5 && conf && conf.ci_low > 0 && conf.level === 'green');
    if (strong) { verdict = 'BET FORT'; tone = 'strong'; }
    else if (top[0] && ((top[0].ev != null && top[0].ev > 0) || top[0].prob >= 65)) { verdict = 'VALUE'; tone = 'value'; }

    return {
      kpi: { verdict, tone, conf_pct: conf && Number.isFinite(conf.accuracy) ? Math.round(conf.accuracy) : null },
      prematch: top,
    };
  } catch (_) { return null; }
}

function toCanonicalTennisMatch(e) {
  const elo = (e.predictions && e.predictions.elo) || null;
  const blended = (e.predictions && e.predictions.blended) || null;
  const pModel = blended
    ? { p1: blended.p1, p2: blended.p2, method: blended.method }
    : (elo ? { p1: elo.p1, p2: elo.p2, method: elo.method } : null);
  const p1 = e.player1 || {};
  const p2 = e.player2 || {};
  const rnd = (o) => (o && Number.isFinite(o.elo) ? Math.round(o.elo) : null);
  return {
    id: e.id,
    tour: e.tour || null,
    tournament: e.tournament || null,
    round: e.round || null,
    surface: e.surface || null,
    surface_source: e.surface_source || null,
    start_time: e.start_time || null,
    status: e.status || null,
    players: {
      p1: {
        name: p1.name || null, country: p1.country || null, flag: p1.flag || null,
        elo_all: elo ? rnd(elo.p1_all) : null,
        elo_surface: elo ? rnd(elo.p1_surface) : null,
        elo_matches: elo ? (elo.p1_matches || 0) : null,
      },
      p2: {
        name: p2.name || null, country: p2.country || null, flag: p2.flag || null,
        elo_all: elo ? rnd(elo.p2_all) : null,
        elo_surface: elo ? rnd(elo.p2_surface) : null,
        elo_matches: elo ? (elo.p2_matches || 0) : null,
      },
    },
    model: pModel ? {
      p1: pModel.p1, p2: pModel.p2, method: pModel.method,
      set_probs: (e.predictions && e.predictions.set_probs) || null,
    } : null,
    market: e.odds ? {
      p1_odds: e.odds.p1 && e.odds.p1.odds, p1_book: e.odds.p1 && e.odds.p1.book,
      p2_odds: e.odds.p2 && e.odds.p2.odds, p2_book: e.odds.p2 && e.odds.p2.book,
      fair: e.fair || null,
    } : null,
    value: {
      edge: e.edge || null,
      ev_model: e.ev_model || null,
      best_market: e.best_edge || null,
      best_model: e.best_ev_model || null,
    },
    confidence: _tennisConfidence(elo),
    log_diff: e.log_diff || null,
    surface_speed: e.surface_speed || null,
    fatigue: e.fatigue || null,
    set_model: e.set_model || null,
    over_under_set_calculations: e.over_under_set_calculations || null,
    predictive: e.predictive || null,
    sources: e.sources || null,
  };
}

async function handleTennisBSD(pathSuffix, cacheKey, ttlMs) {
  if (!BSD_TENNIS_ENABLED) {
    return { status: 503, body: { error: 'tennis_bsd_disabled', fallback: 'espn', detail: 'BSD_TENNIS_ENABLED=false' } };
  }
  if (ttlMs > 0 && cacheKey) {
    const cached = apiCacheGet(cacheKey);
    if (cached) return { status: 200, body: cached, cache: 'hit' };
  }
  try {
    const r = await bsdTennisFetch(pathSuffix);
    if (!r) return { status: 502, body: { error: 'bsd_upstream_error', detail: 'empty response' } };
    if (r.status === 200) {
      if (ttlMs > 0 && cacheKey) apiCacheSet(cacheKey, r.data, 'bsd_tennis', ttlMs);
      return { status: 200, body: r.data, cache: 'miss' };
    }
    return { status: r.status || 502, body: { error: 'bsd_upstream_error', upstream_status: r.status, detail: r.data } };
  } catch (e) {
    if (e && e.code === 'ADDON_REQUIRED') {
      return { status: 402, body: { error: 'addon_required', upgrade_url: e.upgradeUrl, detail: e.message } };
    }
    return { status: 502, body: { error: 'bsd_upstream_error', detail: e.message || String(e) } };
  }
}

